public class Solution { public int[] ProductExceptSelf(int[] nums) { int n = nums.Length; int[] pref = new int[n]; int[] suff = new int[n]; int[] result = new int[n]; pref[0] = 1; suff[n - 1] = 1; for (int i = 1; i < n; i++) { pref[i] = nums[i - 1] * pref[i - 1]; } for (int i = n - 1; i > 0; i--) { suff[i - 1] = nums[i] * suff[i]; } for (int i = 0; i < nums.Length; i++) { result[i] = pref[i] * suff[i]; } return result; } }